import{_ as e,c as t,o as r,ae as i}from"./chunks/framework.CMFi8ROq.js";const p=JSON.parse('{"title":"大语言模型","description":"","frontmatter":{},"headers":[],"relativePath":"ai-guide/LLM.md","filePath":"ai-guide/LLM.md","lastUpdated":1777978720000}'),o={name:"ai-guide/LLM.md"};function n(l,a,s,d,h,c){return r(),t("div",null,a[0]||(a[0]=[i('<h1 id="大语言模型" tabindex="-1">大语言模型 <a class="header-anchor" href="#大语言模型" aria-label="Permalink to &quot;大语言模型&quot;">​</a></h1><p>大语言模型不是一夜之间出现的，而是NLP（自然语言处理，Natural Language Processing）技术演进的结果，Ai 发展的历史可以参考<a href="https://datawhalechina.github.io/easy-vibe/zh-cn/appendix/8-artificial-intelligence/ai-history.html" target="_blank" rel="noreferrer">AI 简史</a>。</p><p>一方面，2017年Google 发布的论文《Attention is All You Need》引入了 Transformer 架构。这相当于给 AI 装上了“注意力机制”。它能同时处理一整段文字，理解单词之间的远距离关联。这是大模型真正的出生证明。另一方面得益于算力的提升，虽然 GPU 不是专门为 AI 设计的，但它的超大规模、可并行的线性代数计算能力，让 AI 的训练和推理速度大幅提升。</p><h2 id="什么是大语言模型" tabindex="-1">什么是大语言模型 <a class="header-anchor" href="#什么是大语言模型" aria-label="Permalink to &quot;什么是大语言模型&quot;">​</a></h2><p>大语言模型（Large Language Model，LLM）是一个基于海量数据训练的、拥有巨量参数的深度学习网络。单从名字上理解，它下面几个特点：</p><ul><li><strong>大</strong>：指参数规模。通常拥有百亿甚至千亿级参数（你可以理解为大脑中的神经元连接）。</li><li><strong>语言</strong>：它的核心输入和输出是人类语言，但也包括代码、数学公式等逻辑语言。</li><li><strong>模型</strong>：它的本质是数学函数。你给它一个输入$x$，它通过复杂的运算给你一个输出 $y$。</li></ul><h2 id="它是如何工作的" tabindex="-1">它是如何工作的 <a class="header-anchor" href="#它是如何工作的" aria-label="Permalink to &quot;它是如何工作的&quot;">​</a></h2>',7)]))}const u=e(o,[["render",n]]);export{p as __pageData,u as default};
